     *
     * Example:
     * findNthLeapYear(2000, 4) => 2008
     * findNthLeapYear(1996, 10) => 2032
     */
    public static int findNthLeapYear(int Y, int N)  {
        int startYear = Y;
        int nextYear = Y + 4;
        int count = 0;
        while (true) {
            if (isLeapYear(startYear)) {
                if (count == N) {
                    return startYear;
                }
                count++;
            }
            startYear = nextYear;
            nextYear += 4;
        }
    }

